// LoadCarModelVariant loads the seasonCarModelVariant's CarModelVariant into the .R struct
func (os SeasonCarModelVariantSlice) LoadCarModelVariant(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carModelVariants, err := os.CarModelVariant(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.CarModelVariant = nil
		o.R.Loaded.CarModelVariant = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	seasonCarModelVariantByKey := make(map[int32][]*SeasonCarModelVariant, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		seasonCarModelVariantByKey[o.CarModelVariantID] = append(seasonCarModelVariantByKey[o.CarModelVariantID], o)
	}

	for _, rel := range carModelVariants {

		owners, ok := seasonCarModelVariantByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.CarModelVariant != nil {
				continue
			}

			rel.R.SeasonCarModelVariants = append(rel.R.SeasonCarModelVariants, o)

			o.R.CarModelVariant = rel

		}
	}

	return nil
}

