type seasonCarModelVariantJoins[Q dialect.Joinable] struct {
	typ             string
	CarModelVariant modAs[Q, carModelVariantColumns]
	Season          modAs[Q, seasonColumns]
}

func (j seasonCarModelVariantJoins[Q]) aliasedAs(alias string) seasonCarModelVariantJoins[Q] {
	return buildSeasonCarModelVariantJoins[Q](buildSeasonCarModelVariantColumns(alias), j.typ)
}

func buildSeasonCarModelVariantJoins[Q dialect.Joinable](cols seasonCarModelVariantColumns, typ string) seasonCarModelVariantJoins[Q] {
	return seasonCarModelVariantJoins[Q]{
		typ: typ,
		CarModelVariant: modAs[Q, carModelVariantColumns]{
			c: CarModelVariants.Columns,
			f: func(to carModelVariantColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModelVariants.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.CarModelVariantID),
					))
				}

				return mods
			},
		},
		Season: modAs[Q, seasonColumns]{
			c: Seasons.Columns,
			f: func(to seasonColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Seasons.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.SeasonID),
					))
				}

				return mods
			},
		},
	}
}
